# Hybrid DNS with Route 53 Resolver
# Resolves on-premises and cloud DNS names

resource "aws_route53_resolver_endpoint" "inbound" {
  name                 = "onprem-to-aws"
  direction            = "INBOUND"
  security_group_ids   = [aws_security_group.resolver.id]

  ip_address {
    subnet_id = aws_subnet.private_1.id
  }
  ip_address {
    subnet_id = aws_subnet.private_2.id
  }
}

# On-premises DNS forwards requests for *.aws.example.com
# to the Route 53 Resolver inbound endpoint IPs

# AWS DNS forwards requests for *.corp.example.com
# to on-premises DNS servers via outbound endpoint

resource "aws_route53_resolver_endpoint" "outbound" {
  name                 = "aws-to-onprem"
  direction            = "OUTBOUND"
  security_group_ids   = [aws_security_group.resolver.id]

  ip_address {
    subnet_id = aws_subnet.private_1.id
  }
}
